#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void lud_diagonal(float *m, float *shadow, int matrix_dim, int offset) {
    int i, j, tx;
    int array_offset;

    // Load diagonal block into shadow
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        array_offset = offset * matrix_dim + offset;
        for (i = 0; i < BLOCK_SIZE; i++) {
            shadow[i * BLOCK_SIZE + tx] = m[array_offset + tx];
            array_offset += matrix_dim;
        }
    }

    // Process diagonal block - LU decomposition within block
    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i; j++)
                shadow[tx * BLOCK_SIZE + i] -= shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            for (j = 0; j < i + 1; j++)
                shadow[(i + 1) * BLOCK_SIZE + tx] -= shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
        }
    }

    // Write back to m
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        array_offset = (offset + 1) * matrix_dim + offset;
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[array_offset + tx] = shadow[i * BLOCK_SIZE + tx];
            array_offset += matrix_dim;
        }
    }
}

void lud_perimeter(float *m, float *dia, float *peri_row, float *peri_col, int matrix_dim, int offset, int bx) {
    int i, j, idx, array_offset;

    // Load diagonal block
    array_offset = offset * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
        }
        array_offset += matrix_dim;
    }

    // Load perimeter row
    array_offset = offset * matrix_dim + (bx + 1) * BLOCK_SIZE;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            peri_row[i * BLOCK_SIZE + idx] = m[array_offset + idx];
        }
        array_offset += matrix_dim;
    }

    // Load perimeter column
    array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx];
        }
        array_offset += matrix_dim;
    }

    // Process perimeter row
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            for (j = 0; j < i; j++)
                peri_row[i * BLOCK_SIZE + idx] -= dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
        }
    }

    // Process perimeter column
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            for (j = 0; j < i; j++)
                peri_col[idx * BLOCK_SIZE + i] -= peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
            peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
        }
    }

    // Write back perimeter row
    array_offset = (offset + 1) * matrix_dim + (bx + 1) * BLOCK_SIZE;
    for (i = 1; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            m[array_offset + idx] = peri_row[i * BLOCK_SIZE + idx];
        }
        array_offset += matrix_dim;
    }

    // Write back perimeter column
    array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
    for (i = 0; i < BLOCK_SIZE; i++) {
        for (idx = 0; idx < BLOCK_SIZE; idx++) {
            m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
        }
        array_offset += matrix_dim;
    }
}

void lud_internal(float *m, float *peri_row, float *peri_col, int matrix_dim, int offset, int bx, int by) {
    int i, tx, ty;
    float sum;

    int global_row_id = offset + (by + 1) * BLOCK_SIZE;
    int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

    // Load perimeter data
    for (ty = 0; ty < BLOCK_SIZE; ty++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
            peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
        }
    }

    // Compute and update internal block
    for (ty = 0; ty < BLOCK_SIZE; ty++) {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            sum = 0;
            for (i = 0; i < BLOCK_SIZE; i++)
                sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
            m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    float *shadow, *dia, *peri_row, *peri_col;
    int i, bx, by;
    int num_blocks;

    shadow = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    dia = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    peri_row = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));
    peri_col = (float *)malloc(BLOCK_SIZE * BLOCK_SIZE * sizeof(float));

    if (!shadow || !dia || !peri_row || !peri_col) {
        if (shadow) free(shadow);
        if (dia) free(dia);
        if (peri_row) free(peri_row);
        if (peri_col) free(peri_col);
        return;
    }

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        // Process diagonal block
        lud_diagonal(m, shadow, matrix_dim, i);

        num_blocks = (matrix_dim - i) / BLOCK_SIZE - 1;

        // Process perimeter blocks
        #pragma omp parallel for
        for (bx = 0; bx < num_blocks; bx++) {
            lud_perimeter(m, dia, peri_row, peri_col, matrix_dim, i, bx);
        }

        // Process internal blocks
        #pragma omp parallel for collapse(2)
        for (by = 0; by < num_blocks; by++) {
            for (bx = 0; bx < num_blocks; bx++) {
                lud_internal(m, peri_row, peri_col, matrix_dim, i, bx, by);
            }
        }
    }

    // Process last diagonal block
    lud_diagonal(m, shadow, matrix_dim, matrix_dim - BLOCK_SIZE);

    free(shadow);
    free(dia);
    free(peri_row);
    free(peri_col);
}
